    bool canConstruct(string s, int k) {
        unordered_map<char, int> mp;
        for (char c : s) {
            mp[c]++;
        }
        int oddCount = 0;
        for (auto it = mp.begin(); it != mp.end(); it++) {
            if (it->second % 2 != 0) {
                oddCount++;
            }
        }
        return oddCount <= k;
    }
};```
